
import { localize } from '../../../../nls.js';
import { registerSize, sizeForAllThemes } from '../sizeUtils.js';

registerSize("bodyFontSize", sizeForAllThemes(13, "px"), ( localize(
    2422,
    "Base font size. This size is used if not overridden by a component."
)));
registerSize("bodyFontSize.small", sizeForAllThemes(12, "px"), ( localize(2423, "Small font size for secondary content.")));
registerSize("bodyFontSize.xSmall", sizeForAllThemes(11, "px"), ( localize(2424, "Extra small font size for less prominent content.")));
registerSize("codiconFontSize", sizeForAllThemes(16, "px"), ( localize(2425, "Base font size for codicons.")));
registerSize("cornerRadius.medium", sizeForAllThemes(6, "px"), ( localize(2426, "Base corner radius for UI elements.")));
registerSize("cornerRadius.xSmall", sizeForAllThemes(2, "px"), ( localize(2427, "Extra small corner radius for very compact UI elements.")));
registerSize("cornerRadius.small", sizeForAllThemes(4, "px"), ( localize(2428, "Small corner radius for compact UI elements.")));
registerSize("cornerRadius.large", sizeForAllThemes(8, "px"), ( localize(2429, "Large corner radius for prominent UI elements.")));
registerSize("cornerRadius.xLarge", sizeForAllThemes(12, "px"), ( localize(2430, "Extra large corner radius for very prominent UI elements.")));
registerSize("cornerRadius.circle", sizeForAllThemes(9999, "px"), ( localize(2431, "Circular corner radius for fully rounded UI elements.")));
registerSize("strokeThickness", sizeForAllThemes(1, "px"), ( localize(2432, "Base stroke thickness for borders and outlines.")));
